import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';

const Login = ({ onLoginSuccess }) => {
    const navigate = useNavigate();
    const [formData, setFormData] = useState({ email: '', password: '' });
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleLogin = async (e) => {
        e.preventDefault();
        setError('');
        setLoading(true);
        try {
            const res = await api.post('/auth/login', formData);
            if (res.data?.token) {
                localStorage.setItem('token', res.data.token);
                localStorage.setItem('user_name', res.data.user?.nama_lengkap || 'User');
                if (onLoginSuccess) onLoginSuccess();
                navigate('/');
            }
        } catch (err) {
            setError(err.response?.data?.message || 'Email atau password salah!');
        } finally {
            setLoading(false);
        }
    };

    const styles = {
        container: { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh', background: '#fffbf7', padding: '20px' },
        card: { width: '100%', maxWidth: '400px', background: '#ffffff', borderRadius: '24px', padding: '40px', boxShadow: '0 10px 25px -5px rgba(0,0,0,0.1)', border: '1px solid #e5e7eb' },
        brand: { textAlign: 'center', marginBottom: '32px' },
        logo: { fontSize: '24px', fontWeight: '800', color: '#ea580c', margin: 0 },
        title: { fontSize: '20px', fontWeight: '700', color: '#1f2937', marginBottom: '8px' },
        label: { fontSize: '12px', fontWeight: '600', color: '#4b5563', display: 'block', marginBottom: '8px' },
        input: { width: '100%', padding: '12px 16px', borderRadius: '10px', border: '1px solid #d1d5db', fontSize: '14px', marginBottom: '16px', boxSizing: 'border-box' },
        btn: { width: '100%', padding: '12px', borderRadius: '10px', border: 'none', background: '#ea580c', color: '#fff', fontWeight: '600', cursor: 'pointer', marginTop: '8px' },
        btnGuest: { width: '100%', padding: '12px', borderRadius: '10px', border: '1px solid #ea580c', background: 'transparent', color: '#ea580c', fontWeight: '600', cursor: 'pointer', marginTop: '12px' },
        footer: { textAlign: 'center', marginTop: '24px', fontSize: '14px', color: '#6b7280' }
    };

    return (
        <div style={styles.container}>
            <div style={styles.card}>
                <div style={styles.brand}>
                    <h1 style={styles.logo}>YerusSolo</h1>
                </div>
                <h2 style={styles.title}>Masuk Akun</h2>
                {error && <p style={{ color: '#dc2626', fontSize: '12px', marginBottom: '16px' }}>{error}</p>}
                <form onSubmit={handleLogin}>
                    <label style={styles.label}>Email</label>
                    <input type="email" name="email" value={formData.email} onChange={handleChange} style={styles.input} required />
                    <label style={styles.label}>Password</label>
                    <input type="password" name="password" value={formData.password} onChange={handleChange} style={styles.input} required />
                    <button type="submit" style={styles.btn} disabled={loading}>{loading ? 'Memproses...' : 'Masuk'}</button>
                </form>
                <button type="button" onClick={() => navigate('/')} style={styles.btnGuest}>Jelajahi Sebagai Guest</button>
                <p style={styles.footer}>Belum punya akun? <span onClick={() => navigate('/register')} style={{ color: '#ea580c', cursor: 'pointer', fontWeight: '700' }}>Daftar</span></p>
            </div>
        </div>
    );
};

export default Login;
